#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim)
{
    int i, j, k, l, p, offset;
    float sum;
    int block_count;

    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {
        // Diagonal block processing
        for (i = 0; i < BLOCK_SIZE; i++) {
            // Upper triangular - parallelize j loop
            #pragma omp parallel for
            for (j = i; j < BLOCK_SIZE; j++) {
                sum = m[(offset + i) * matrix_dim + offset + j];
                for (k = 0; k < i; k++) {
                    sum -= m[(offset + i) * matrix_dim + offset + k] * m[(offset + k) * matrix_dim + offset + j];
                }
                m[(offset + i) * matrix_dim + offset + j] = sum;
            }

            // Lower triangular - parallelize j loop
            if (i < BLOCK_SIZE - 1) {
                #pragma omp parallel for
                for (j = i + 1; j < BLOCK_SIZE; j++) {
                    sum = m[(offset + j) * matrix_dim + offset + i];
                    for (k = 0; k < i; k++) {
                        sum -= m[(offset + j) * matrix_dim + offset + k] * m[(offset + k) * matrix_dim + offset + i];
                    }
                    m[(offset + j) * matrix_dim + offset + i] = sum / m[(offset + i) * matrix_dim + offset + i];
                }
            }
        }

        block_count = (matrix_dim - offset) / BLOCK_SIZE - 1;

        // Perimeter processing - parallelize i loop
        #pragma omp parallel for
        for (i = 0; i < block_count; i++) {
            // Row perimeter
            for (j = 1; j < BLOCK_SIZE; j++) {
                for (k = 0; k < BLOCK_SIZE; k++) {
                    sum = m[(offset + j) * matrix_dim + offset + BLOCK_SIZE + i * BLOCK_SIZE + k];
                    for (l = 0; l < j; l++) {
                        sum -= m[(offset + j) * matrix_dim + offset + l] * m[(offset + l) * matrix_dim + offset + BLOCK_SIZE + i * BLOCK_SIZE + k];
                    }
                    m[(offset + j) * matrix_dim + offset + BLOCK_SIZE + i * BLOCK_SIZE + k] = sum;
                }
            }

            // Column perimeter
            for (j = 0; j < BLOCK_SIZE; j++) {
                for (k = 0; k < BLOCK_SIZE; k++) {
                    sum = m[(offset + BLOCK_SIZE + i * BLOCK_SIZE + k) * matrix_dim + offset + j];
                    for (l = 0; l < j; l++) {
                        sum -= m[(offset + BLOCK_SIZE + i * BLOCK_SIZE + k) * matrix_dim + offset + l] * m[(offset + l) * matrix_dim + offset + j];
                    }
                    m[(offset + BLOCK_SIZE + i * BLOCK_SIZE + k) * matrix_dim + offset + j] = sum / m[(offset + j) * matrix_dim + offset + j];
                }
            }
        }

        // Internal block processing - parallelize i and j loops
        #pragma omp parallel for
        for (i = 0; i < block_count; i++) {
            for (j = 0; j < block_count; j++) {
                for (k = 0; k < BLOCK_SIZE; k++) {
                    for (l = 0; l < BLOCK_SIZE; l++) {
                        sum = m[(offset + BLOCK_SIZE + i * BLOCK_SIZE + k) * matrix_dim + offset + BLOCK_SIZE + j * BLOCK_SIZE + l];
                        for (p = 0; p < BLOCK_SIZE; p++) {
                            sum -= m[(offset + BLOCK_SIZE + i * BLOCK_SIZE + k) * matrix_dim + offset + p] * m[(offset + p) * matrix_dim + offset + BLOCK_SIZE + j * BLOCK_SIZE + l];
                        }
                        m[(offset + BLOCK_SIZE + i * BLOCK_SIZE + k) * matrix_dim + offset + BLOCK_SIZE + j * BLOCK_SIZE + l] = sum;
                    }
                }
            }
        }
    }

    // Final diagonal block - parallelize i loop
    offset = matrix_dim - BLOCK_SIZE;
    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = i; j < BLOCK_SIZE; j++) {
            sum = m[(offset + i) * matrix_dim + offset + j];
            for (k = 0; k < i; k++) {
                sum -= m[(offset + i) * matrix_dim + offset + k] * m[(offset + k) * matrix_dim + offset + j];
            }
            m[(offset + i) * matrix_dim + offset + j] = sum;
        }
    }
}
